1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE = 0.1;
7	const COMPONENT_BLOCK_SIZE = 3;
8	const COMPONENT_BLOCK_PRICE = 60;
9	
10	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	
21	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
22	
23	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
24	
25	const priceForComponentGroup = (type: string, count: number): number =>
26	  count === COMPONENT_BLOCK_SIZE
27	    ? COMPONENT_BLOCK_PRICE
28	    : count * BASE_PREMIUM_BY_TYPE[type];
29	
30	const countByType = (items: Item[]): Map<string, number> => {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  return counts;
36	};
37	
38	const sumBasePremiumsFor = (items: Item[]): number => {
39	  const mainItemsTotal = items
40	    .filter((item) => !isComponent(item))
41	    .reduce((sum, item) => sum + basePremiumOf(item), 0);
42	
43	  const componentsTotal = Array.from(countByType(items.filter(isComponent)))
44	    .reduce((sum, [type, count]) => sum + priceForComponentGroup(type, count), 0);
45	
46	  return mainItemsTotal + componentsTotal;
47	};
48	
49	const computePremium = (items: Item[]): number => {
50	  const base = sumBasePremiumsFor(items);
51	  const withFirstInsurance = base * (1 + FIRST_INSURANCE_SURCHARGE);
52	  return withFirstInsurance + PROCESSING_FEE;
53	};
54	
55	// Rounds up to the nearest whole gold piece, in MHPCO's favor.
56	// Cleans float noise (e.g. 66.00000000000001) before ceiling.
57	const roundUpToGold = (amount: number): number =>
58	  Math.ceil(Math.round(amount * 1e6) / 1e6);
59	
60	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
61	  const results = scenario.steps.map((step) => ({
62	    premium: roundUpToGold(computePremium(step.items)),
63	  }));
64	  return { results };
65	};
